// Generate formatted report from data
const input = $input.first().json;

const report_type = input.report_type || 'generic';
const title = input.title || 'System Report';
const format = input.format || 'markdown';
const generated_at = new Date().toISOString();
const report_id = `rpt_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

let data;
try {
  data = typeof input.data === 'string' ? JSON.parse(input.data) : (input.data || {});
} catch (e) {
  data = { raw: input.data, parse_error: e.message };
}

function statusEmoji(status) {
  const map = { success: '✅', ok: '✅', failed: '❌', critical: '🚨', warning: '⚠️', error: '❌', partial: '🔶', info: 'ℹ️' };
  return map[String(status).toLowerCase()] || '❓';
}

function severityEmoji(severity) {
  const map = { critical: '🚨', error: '❌', warning: '⚠️', info: 'ℹ️', ok: '✅' };
  return map[String(severity).toLowerCase()] || '❓';
}

function formatBytes(mb) {
  if (mb > 1024) return `${(mb/1024).toFixed(1)} GB`;
  return `${mb} MB`;
}

let report_content = '';

if (format === 'markdown') {
  const hr = '---';
  const now = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

  report_content += `# ${title}\n\n`;
  report_content += `**Erstellt:** ${now}  \n`;
  report_content += `**Report ID:** \`${report_id}\`  \n`;
  report_content += `**Typ:** ${report_type}  \n\n`;
  report_content += `${hr}\n\n`;

  if (report_type === 'update') {
    // Update report format
    const systems = Array.isArray(data) ? data : (data.results || [data]);
    const total = systems.length;
    const success = systems.filter(s => s.status === 'success').length;
    const failed = systems.filter(s => s.status === 'failed').length;
    const partial = systems.filter(s => s.status === 'partial').length;
    const rebootNeeded = systems.filter(s => s.reboot_required).length;

    report_content += `## 📊 Zusammenfassung\n\n`;
    report_content += `| Metrik | Wert |\n|--------|------|\n`;
    report_content += `| Systeme gesamt | ${total} |\n`;
    report_content += `| ✅ Erfolgreich | ${success} |\n`;
    report_content += `| ❌ Fehlgeschlagen | ${failed} |\n`;
    report_content += `| 🔶 Teilweise | ${partial} |\n`;
    report_content += `| 🔄 Neustart nötig | ${rebootNeeded} |\n\n`;

    report_content += `## 📋 Details\n\n`;
    report_content += `| System | Typ | Pakete | Status | Neustart |\n|--------|-----|--------|--------|----------|\n`;
    for (const sys of systems) {
      const emoji = statusEmoji(sys.status);
      const reboot = sys.reboot_required ? '⚠️ Ja' : '✅ Nein';
      report_content += `| ${sys.name || 'N/A'} | ${sys.type || 'N/A'} | ${sys.packages_updated || 0} | ${emoji} ${sys.status} | ${reboot} |\n`;
    }

  } else if (report_type === 'analyse' || report_type === 'health') {
    // Analysis / health report format
    const systems = Array.isArray(data) ? data : (data.results || [data]);
    const critical = systems.filter(s => s.health_status === 'critical' || (s.issues && s.issues.some(i => i.severity === 'critical'))).length;
    const warning = systems.filter(s => s.health_status === 'warning' || s.has_issues).length;
    const ok = systems.filter(s => s.health_status === 'ok' && !s.has_issues).length;

    report_content += `## 📊 Health Overview\n\n`;
    report_content += `| Status | Anzahl |\n|--------|--------|\n`;
    report_content += `| 🚨 Critical | ${critical} |\n`;
    report_content += `| ⚠️ Warning | ${warning} |\n`;
    report_content += `| ✅ OK | ${ok} |\n\n`;

    report_content += `## 🖥️ Systemdetails\n\n`;
    for (const sys of systems) {
      const hEmoji = statusEmoji(sys.health_status || 'ok');
      report_content += `### ${hEmoji} ${sys.name || 'Unknown'} (${sys.type || 'N/A'})\n\n`;
      if (sys.disk_usage_pct !== undefined) {
        report_content += `- 💽 Disk: ${sys.disk_usage_pct}%\n`;
        report_content += `- 🧠 Memory: ${sys.memory_usage_pct}%\n`;
        report_content += `- ⚡ CPU Load: ${sys.cpu_load}\n`;
        report_content += `- 🔧 Services: ${sys.services_ok ? '✅ OK' : '❌ Fehler'}\n`;
      }
      if (sys.issues && sys.issues.length > 0) {
        report_content += `\n**Issues:**\n`;
        for (const issue of sys.issues.slice(0, 5)) {
          report_content += `- ${severityEmoji(issue.severity)} [${issue.severity.toUpperCase()}] ${issue.message}\n`;
        }
      }
      report_content += `\n`;
    }

  } else if (report_type === 'incident') {
    // Incident report format
    report_content += `## 🚨 Incident Details\n\n`;
    report_content += `| Feld | Wert |\n|------|------|\n`;
    report_content += `| Host | ${data.host || 'N/A'} |\n`;
    report_content += `| Severity | ${severityEmoji(data.severity)} ${data.severity || 'N/A'} |\n`;
    report_content += `| Trigger | ${data.trigger || 'N/A'} |\n`;
    report_content += `| Alert Time | ${data.alert_time || 'N/A'} |\n\n`;

    if (data.rca) {
      report_content += `## 🔍 Root Cause Analysis\n\n${data.rca}\n\n`;
    }
    if (data.remediation) {
      report_content += `## 🔧 Durchgeführte Maßnahmen\n\n${data.remediation}\n\n`;
    }

  } else {
    // Generic format
    report_content += `## Daten\n\n\`\`\`json\n${JSON.stringify(data, null, 2)}\n\`\`\`\n`;
  }

  report_content += `\n${hr}\n_Generiert automatisch durch n8n Workflow-System_\n`;

} else if (format === 'html') {
  // Basic HTML format
  report_content = `<!DOCTYPE html><html><head><title>${title}</title></head><body>`;
  report_content += `<h1>${title}</h1>`;
  report_content += `<p>Generated: ${generated_at}</p>`;
  report_content += `<pre>${JSON.stringify(data, null, 2)}</pre>`;
  report_content += `</body></html>`;
} else {
  report_content = JSON.stringify({ title, generated_at, data }, null, 2);
}

return [{
  json: {
    report_id,
    report_content,
    format,
    report_type,
    title,
    generated_at,
    char_count: report_content.length
  }
}];
